# main.py# === Import your project modules ===from loaders.raman_loader import select_directory, select_file, load_ramanfrom preprocessors.raman_preprocess import preprocess_pipeline_1, preprocess_pipeline_2, group_preprocess, group_preprocess_2, avg_y_blockfrom preprocessors.aligner import align_xy, align_group_xyimport osimport pandas as pdfrom models.run_loops import run_regression_loop, run_classification_loopimport numpy as npfrom models.prediction_eval import evaluate_on_prediction_set# === Step 1: Select Raw Data Directory ===print("\n📂 Select the directory containing your raw Raman .spc files:")directory = select_directory()# === Step 2: Set up Output Directories ===spectra_dir = os.path.join(directory, "Raman_Spectra")results_dir = os.path.join(directory, "Model_Results")os.makedirs(spectra_dir, exist_ok=True)os.makedirs(results_dir, exist_ok=True)# === Step 3: Load Raw Raman Spectra ===sample_spectra, shifts, sample_groups = load_raman(directory, spectra_dir)# === Step 4: Preprocess Spectra ===preprocessed_sample_spectra, cropped_axis = preprocess_pipeline_2(sample_spectra, spectra_dir)#preprocessed_group_spectra, cropped_axis = group_preprocess_2(sample_spectra, sample_groups, spectra_dir)# === Step 5: Load Target Table (GCMS or Metadata) ===print("\n📄 Select the GCMS or Target Excel file:")gcms_path = select_file()gcms_df = pd.read_excel(gcms_path)gcms_df.set_index('ID', inplace=True)gcms_group_df = avg_y_block(gcms_df)# === Step 6: Align X and Y ===filtered_X, filtered_Y, filtered_sample_ids, filtered_groups = align_xy(preprocessed_sample_spectra, gcms_df)#filtered_X, filtered_Y, filtered_sample_ids, filtered_groups = align_group_xy(preprocessed_group_spectra, gcms_group_df)# === Step 7: Modeling Loops ===model_results = run_regression_loop(filtered_X, filtered_Y, results_dir, cropped_axis, groups=None, manual_param=4)#run_classification_loop(filtered_X, filtered_Y, results_dir, cropped_axis, groups=filtered_groups)# === Optional: Load Prediction X and Y ===print("\n (Optional) Select directory with prediction spectra:")pred_dir = select_directory()if pred_dir:    pred_sample_spectra, _, _= load_raman(pred_dir, spectra_dir)    pred_preprocessed_sample_spectra, _ = preprocess_pipeline_2(pred_sample_spectra, spectra_dir)    # Flatten to X_pred array    X_pred = np.vstack([        spectrum.spectral_data        for spectra in pred_preprocessed_sample_spectra.values()        for spectrum in spectra    ])else:    X_pred = None    filtered_X_pred = None    filtered_Y_pred = Noneprint("\n📄 (Optional) Select Y-block file for prediction set:")y_pred_df = NoneY_pred_true = Noney_pred_path = select_file()if y_pred_path:    y_pred_df = pd.read_excel(y_pred_path)    y_pred_df.set_index('ID', inplace=True)else:    Y_pred_true = None# === Align Prediction X and Y (if both provided) ===if pred_dir and y_pred_df is not None:    filtered_X_pred, filtered_Y_pred, filtered_pred_sample_ids, filtered_pred_groups = align_xy(        pred_preprocessed_sample_spectra, y_pred_df    )    Y_pred_true = filtered_Y_pred.valueselse:    filtered_X_pred = X_pred  # still usable even if no Y    Y_pred_true = Noneif filtered_X_pred is not None:    for i, analyte in enumerate(filtered_Y.columns):        model_obj = model_results[analyte]        evaluate_on_prediction_set(            model=model_obj['model'],            X_pred=filtered_X_pred,            y_mean=model_obj['cv_results']['y_mean'],            axis=cropped_axis,            analyte=analyte,            directory=results_dir,            Y_pred_true=Y_pred_true[:, i] if Y_pred_true is not None else None,            model_name="PLS",            sample_ids=filtered_pred_sample_ids        )